use base64::Engine;
use gio::prelude::CancellableExt;
use image::{DynamicImage, ImageFormat, Rgba, RgbaImage};

use diorama::image::{DecodeLimits, probe_decode};

// Upstream Glycin HEIC integration fixture:
// https://gitlab.gnome.org/sophie-h/test-images/-/blob/main/images/animated-numbers/animated-numbers.heic
const HEIC_FIXTURE: &str = "";

#[test]
fn required_release_formats_decode_through_glycin() {
    let directory = tempfile::tempdir().unwrap();
    let pixels = RgbaImage::from_fn(4, 3, |x, y| {
        Rgba([(x * 50) as u8, (y * 70) as u8, 120, 255])
    });
    let image = DynamicImage::ImageRgba8(pixels);
    let formats = [
        ("sample.png", ImageFormat::Png),
        ("sample.jpg", ImageFormat::Jpeg),
        ("sample.gif", ImageFormat::Gif),
        ("sample.webp", ImageFormat::WebP),
        ("sample.avif", ImageFormat::Avif),
        ("sample.tiff", ImageFormat::Tiff),
    ];
    let mut paths = Vec::new();
    for (name, format) in formats {
        let path = directory.path().join(name);
        image.save_with_format(&path, format).unwrap();
        paths.push(path);
    }
    let svg = directory.path().join("sample.svg");
    std::fs::write(
        &svg,
        r#"<svg xmlns="http://www.w3.org/2000/svg" width="4" height="3"><rect width="4" height="3" fill="red"/></svg>"#,
    )
    .unwrap();
    paths.push(svg);
    let heic = directory.path().join("sample.heic");
    std::fs::write(
        &heic,
        base64::engine::general_purpose::STANDARD
            .decode(HEIC_FIXTURE)
            .unwrap(),
    )
    .unwrap();
    paths.push(heic);

    let context = glib::MainContext::default();
    for path in paths {
        let file = gio::File::for_path(&path);
        let cancellable = gio::Cancellable::new();
        let probe = context
            .block_on(probe_decode(&file, DecodeLimits::default(), &cancellable))
            .unwrap_or_else(|error| panic!("{}: {error}", path.display()));
        assert!(probe.width > 0, "{}", path.display());
        assert!(probe.height > 0, "{}", path.display());
        assert!(!probe.mime_type.is_empty(), "{}", path.display());
        assert!(!cancellable.is_cancelled());
    }
}
